@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public int TimeoutSeconds { get; set; } = 300;

    [Parameter] public EventCallback OnIdle { get; set; }

    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import",
            "./_content/sv-db6cf01f555f41659a8d200f3d0fdbd7/Components/UserActivityTracker.razor.js");

        await _module.InvokeVoidAsync("init", _dotNetRef, TimeoutSeconds * 1000);
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
            }
            catch (JSDisconnectedException) { }
            try
            {
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        _dotNetRef?.Dispose();
    }
}

let dotNetRef = null;
let timeoutMs = 300000;
let timerId = null;
let isIdle = false;

const events = ['mousemove', 'keydown', 'click', 'scroll'];

function resetTimer() {
    clearTimeout(timerId);

    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('OnActiveCallback');
    }

    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnIdleCallback');
    }, timeoutMs);
}

function handleEvent() {
    resetTimer();
}

export function init(ref, timeout) {
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(e => document.addEventListener(e, handleEvent, { passive: true }));
    resetTimer();
}

export function dispose() {
    clearTimeout(timerId);
    timerId = null;
    events.forEach(e => document.removeEventListener(e, handleEvent));
    dotNetRef = null;
    isIdle = false;
}

